package main

import "fmt"

func main() {
    // ---- Array declaration ----
    var arr1 [3]int
    arr2 := [3]int{1, 2, 3}
    arr3 := [...]int{4, 5, 6, 7}  // Compiler counts

    fmt.Println("arr1:", arr1)
    fmt.Println("arr2:", arr2)
    fmt.Println("arr3:", arr3)

    // ---- Accessing elements ----
    arr := [5]int{10, 20, 30, 40, 50}
    fmt.Println("First:", arr[0])
    fmt.Println("Last:", arr[4])

    // ---- Modifying elements ----
    arr[0] = 99
    fmt.Println("After modification:", arr)

    // ---- Array length ----
    fmt.Println("Length:", len(arr))

    // ---- Iterating over array ----
    for i := 0; i < len(arr); i++ {
        fmt.Printf("arr[%d] = %d\n", i, arr[i])
    }

    // ---- Range over array ----
    for i, v := range arr {
        fmt.Printf("Index %d: %d\n", i, v)
    }

    // ---- Arrays are values, not references ----
    arr4 := arr  // Copy!
    arr4[0] = 999
    fmt.Println("Original:", arr)
    fmt.Println("Copy:", arr4)

    // ---- Multidimensional arrays ----
    matrix := [2][3]int{
        {1, 2, 3},
        {4, 5, 6},
    }

    fmt.Println("Matrix:", matrix)
    fmt.Println("matrix[0][1]:", matrix[0][1])

    // ---- Comparing arrays ----
    a := [3]int{1, 2, 3}
    b := [3]int{1, 2, 3}
    c := [3]int{4, 5, 6}

    fmt.Println("a == b:", a == b)
    fmt.Println("a == c:", a == c)

    // ---- Array of strings ----
    names := [3]string{"Hero", "Aragorn", "Gandalf"}
    for _, name := range names {
        fmt.Println("Name:", name)
    }
}

