package main

import "fmt"

func main() {
    arr := [5]int{10, 20, 30, 40, 50}
    fmt.Println("Array:", arr)

    arr[2] = 99
    fmt.Println("After change:", arr)

    fmt.Println("Length:", len(arr))

    for i, v := range arr {
        fmt.Printf("Index %d: %d\n", i, v)
    }
}
